import{_ as a,o as e,c as o,a3 as r}from"./chunks/framework.Daqi0Atb.js";const n="/assets/01-01.C1SAG5OX.jpg",c=JSON.parse('{"title":"01｜范式之变：GoF 的崩塌和分布式的血脉进化","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/01-范式之变：GoF的崩塌和分布式的血脉进化.md","filePath":"courses/agent-design/01-范式之变：GoF的崩塌和分布式的血脉进化.md"}'),s={name:"courses/agent-design/01-范式之变：GoF的崩塌和分布式的血脉进化.md"};function l(i,t,d,h,g,u){return e(),o("div",null,[...t[0]||(t[0]=[r('<h1 id="_01-范式之变-gof-的崩塌和分布式的血脉进化" tabindex="-1">01｜范式之变：GoF 的崩塌和分布式的血脉进化 <a class="header-anchor" href="#_01-范式之变-gof-的崩塌和分布式的血脉进化" aria-label="Permalink to &quot;01｜范式之变：GoF 的崩塌和分布式的血脉进化&quot;">​</a></h1><p><strong>作者</strong>：黄佳</p><hr><h2 id="一句话脉络" tabindex="-1">一句话脉络 <a class="header-anchor" href="#一句话脉络" aria-label="Permalink to &quot;一句话脉络&quot;">​</a></h2><ul><li>GoF 解决&quot;代码怎么组织&quot; → 分布式解决&quot;服务怎么存活&quot; → <strong>Agent 解决&quot;模型怎么被约束地行动&quot;</strong></li><li>第二代不是推翻第一代，第三代不是推翻第三代——是问题层次往上推进了一层</li></ul><p><img src="'+n+`" alt="三代设计模式演进"></p><hr><h2 id="gof-底层假设-四个" tabindex="-1">GoF 底层假设（四个） <a class="header-anchor" href="#gof-底层假设-四个" aria-label="Permalink to &quot;GoF 底层假设（四个）&quot;">​</a></h2><p>单进程 / 共享内存 / 同步调用 / 确定性失败</p><p>这四个假设在 2010 年代分布式时代已经开始受冲击，到了 2024 年 Agent 时代彻底不够用了。</p><hr><h2 id="分布式模式对-gof-假设的冲击" tabindex="-1">分布式模式对 GoF 假设的冲击 <a class="header-anchor" href="#分布式模式对-gof-假设的冲击" aria-label="Permalink to &quot;分布式模式对 GoF 假设的冲击&quot;">​</a></h2><table tabindex="0"><thead><tr><th>GoF 假设</th><th>分布式现实</th></tr></thead><tbody><tr><td>共享内存</td><td>网络分区，节点间不能瞬间看到对方状态</td></tr><tr><td>同步调用</td><td>异步消息，调用方等不到响应可能是消息丢了</td></tr><tr><td>单点失败</td><td>部分失败，30% 节点挂了系统仍要工作</td></tr><tr><td>确定性</td><td>CAP 三选二，不能全要</td></tr></tbody></table><p><strong>分布式 9 个核心模式的共同特征</strong>：把&quot;不确定性&quot;作为首要关注点来处理。失败不是 Exception，是 default。</p><h2 id="gof-四种模式在-agent-时代的断裂" tabindex="-1">GoF 四种模式在 Agent 时代的断裂 <a class="header-anchor" href="#gof-四种模式在-agent-时代的断裂" aria-label="Permalink to &quot;GoF 四种模式在 Agent 时代的断裂&quot;">​</a></h2><h3 id="_1-singleton-断裂" tabindex="-1">1. Singleton 断裂 <a class="header-anchor" href="#_1-singleton-断裂" aria-label="Permalink to &quot;1. Singleton 断裂&quot;">​</a></h3><p><strong>经典假设</strong>：状态全局共享，所有调用者看到同一份内存里的同一份数据。</p><p><strong>Agent 现实</strong>：上下文窗口有 token 上限，每次对话会被重置。你在第一次对话里放的&quot;全局配置&quot;，上下文压缩时可能消失；新对话时 Agent 压根没见过。</p><p><strong>→ 需要的不是 Singleton，是分层记忆架构</strong>（工作记忆 / 短期记忆 / 长期记忆 / 程序性记忆）</p><hr><h3 id="_2-factory-断裂" tabindex="-1">2. Factory 断裂 <a class="header-anchor" href="#_2-factory-断裂" aria-label="Permalink to &quot;2. Factory 断裂&quot;">​</a></h3><p><strong>经典假设</strong>：产品类型在编译时已知，<code>createSedan() / createSUV()</code>。</p><p><strong>Agent 现实</strong>：Agent 的&quot;产品&quot;是动作，而动作空间在编译期是开放的。MCP 协议让 Agent 在运行时动态发现新工具——明天可能接到一个今天不存在的 MCP server。</p><p><strong>→ 需要的是语义工具路由（Semantic Tool Routing）</strong>，让 Agent 根据自然语言意图动态匹配工具描述</p><hr><h3 id="_3-observer-断裂" tabindex="-1">3. Observer 断裂 <a class="header-anchor" href="#_3-observer-断裂" aria-label="Permalink to &quot;3. Observer 断裂&quot;">​</a></h3><p><strong>经典假设</strong>：推送可靠且廉价，状态变化触发回调，所有 subscribers 立刻收到。</p><p><strong>Agent 现实</strong>：DOM 节点几百个，全推给 Agent 做 Observer，上下文窗口秒爆；logstream 一秒一万条，每条都推送，token 烧完还没开始想事情。</p><p><strong>→ 需要的是主动感知（Active Perception）</strong>，Agent 自己决定看什么、什么时候看、看多深</p><hr><h3 id="_4-strategy-断裂-最有代表性" tabindex="-1">4. Strategy 断裂（最有代表性） <a class="header-anchor" href="#_4-strategy-断裂-最有代表性" aria-label="Permalink to &quot;4. Strategy 断裂（最有代表性）&quot;">​</a></h3><p><strong>经典假设</strong>：开发者编码时决定用哪个策略，<code>calculator.setStrategy(new VIPPricing())</code>。</p><p><strong>Agent 现实</strong>：Claude Code 修 bug 的 7 步里，没有任何一次 <code>setStrategy()</code> 调用。每一步的策略选择都是 LLM 在运行时自己做的：</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>看到 lock 用法可疑 → 切到 race condition</span></span>
<span class="line"><span>假设&quot;不是 timing 问题&quot; → 切到 stale data</span></span>
<span class="line"><span>假设需要看更多 caller → 切到 grep mode</span></span>
<span class="line"><span>寻找所有 cache.get 调用点</span></span></code></pre></div><p><strong>→ Strategy 模式没消失，是被搬到了 Agent 脑子里，由 LLM 在每一步动态切换</strong></p><hr><h2 id="断裂的根因-决策权从开发者搬到大模型" tabindex="-1">断裂的根因：决策权从开发者搬到大模型 <a class="header-anchor" href="#断裂的根因-决策权从开发者搬到大模型" aria-label="Permalink to &quot;断裂的根因：决策权从开发者搬到大模型&quot;">​</a></h2><p>GoF 所有模式假设：<strong>架构师在设计时做出所有结构性决策</strong></p><p>Agent 系统要求：<strong>系统本身在运行时、不确定性情况下做出决策</strong></p><ul><li>GoF 时代：编译期决策 + 运行时执行</li><li>Agent 时代：运行时决策 + 运行时执行</li></ul><p>决策权从开发者手里搬到 LLM——这个搬家足以让 GoF 整个 23 模式集体失重。</p><h3 id="对照表" tabindex="-1">对照表 <a class="header-anchor" href="#对照表" aria-label="Permalink to &quot;对照表&quot;">​</a></h3><table tabindex="0"><thead><tr><th>GoF 模式</th><th>Agent 时代的对应</th></tr></thead><tbody><tr><td>Singleton</td><td>MemoryArchitecture（04 记忆模块 · 4 层记忆）</td></tr><tr><td>Factory</td><td>SemanticToolRouter（04 行动模块 · 工具调用和 MCP 语义匹配）</td></tr><tr><td>Observer</td><td>ActivePerception（02 感知模块 · Agent 自己决定看什么）</td></tr><tr><td>Strategy</td><td>LLM 在 reason() 里每一步自己挑</td></tr></tbody></table><hr><h2 id="三种不确定性-agent-时代的新地基" tabindex="-1">三种不确定性（Agent 时代的新地基） <a class="header-anchor" href="#三种不确定性-agent-时代的新地基" aria-label="Permalink to &quot;三种不确定性（Agent 时代的新地基）&quot;">​</a></h2><h3 id="_1-输出不确定-output-uncertainty" tabindex="-1">1. 输出不确定（Output uncertainty） <a class="header-anchor" href="#_1-输出不确定-output-uncertainty" aria-label="Permalink to &quot;1. 输出不确定（Output uncertainty）&quot;">​</a></h3><p>同一个 prompt 跑十次，给十种不同答案。传统软件 retry 假设幂等，失败重跑得同样结果；LLM retry 可能得到完全不一样的答案，引出新的行为分支。</p><p>→ 熔断器（Circuit Breaker）、幂等键（Idempotency-Key）整套要重新装</p><h3 id="_2-行为不确定-behavioral-uncertainty" tabindex="-1">2. 行为不确定（Behavioral uncertainty） <a class="header-anchor" href="#_2-行为不确定-behavioral-uncertainty" aria-label="Permalink to &quot;2. 行为不确定（Behavioral uncertainty）&quot;">​</a></h3><p>Agent 自己决定要不要调用工具、先调哪个、要不要问澄清问题、要不要继续展开。行为轨迹不再是代码里写死的流程图。ReAct Agent 在 Reasoning 和 Acting 之间循环切换，长度、内容、每步做什么，不是设计阶段能预测的。</p><h3 id="_3-环境不确定-environmental-uncertainty" tabindex="-1">3. 环境不确定（Environmental uncertainty） <a class="header-anchor" href="#_3-环境不确定-environmental-uncertainty" aria-label="Permalink to &quot;3. 环境不确定（Environmental uncertainty）&quot;">​</a></h3><p>Agent 操作的世界本身在变。今天看到的页面布局明天可能变了；上次读过的 Codebase 这次可能已被同事改过。世界不会停下来等 Agent。</p><hr><h2 id="核心判断-把不确定性当作默认运行条件" tabindex="-1">核心判断：把不确定性当作默认运行条件 <a class="header-anchor" href="#核心判断-把不确定性当作默认运行条件" aria-label="Permalink to &quot;核心判断：把不确定性当作默认运行条件&quot;">​</a></h2><blockquote><p><strong>传统软件工程把不确定性当边缘情况来处理（try-catch 一下）。Agent 工程必须把不确定性当作默认运行条件。</strong></p></blockquote><p>也就是说，要从一开始就默认系统会漂、会偏、会重复、会失控，在这个前提下设计结构，不能等出了问题再打补丁。</p><hr><h2 id="harness-新一代工程地基" tabindex="-1">Harness：新一代工程地基 <a class="header-anchor" href="#harness-新一代工程地基" aria-label="Permalink to &quot;Harness：新一代工程地基&quot;">​</a></h2><h3 id="定义" tabindex="-1">定义 <a class="header-anchor" href="#定义" aria-label="Permalink to &quot;定义&quot;">​</a></h3><p>当系统的关键决策越来越多地在运行时由模型作出时，工程师的工作重心从&quot;写功能逻辑&quot;变成&quot;设计边界条件&quot;：</p><ul><li>模型在什么上下文下思考</li><li>模型能看到哪些信息</li><li>模型能调哪些工具</li><li>模型在什么条件下必须停下来</li><li>模型做错以后，系统如何把它拉回来</li><li>模型做过什么，谁来留痕，谁来审计</li></ul><p><strong>这一整层不是 prompt。这一整层就是 Harness。</strong></p><p>Harness 在模型思考之前、之中、之后，给它立边界、留痕迹、做审计。它不替代模型思考。</p><h3 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h3><blockquote><p><strong>Agent 架构，就是在不确定性之下设计有界资源的分配。</strong> Agent architecture is the design of bounded resource allocation under uncertainty.</p><p><strong>模型负责花钱，Harness 负责管账。</strong></p></blockquote><p>模型天然擅长生成可能性，但不天然擅长节制。它会花、会试、会探索、会走弯路。问题是它花到哪里、花多少、什么时候该停——模型会花是默认前提。</p><p>Harness 的意义：不负责创造智能，负责约束智能的开销与后果。</p><h3 id="工程杠杆" tabindex="-1">工程杠杆 <a class="header-anchor" href="#工程杠杆" aria-label="Permalink to &quot;工程杠杆&quot;">​</a></h3><ul><li>调 prompt = 局部修补，让&quot;这次别犯&quot;</li><li>做 Harness = 把局部错误上升为系统纪律，让&quot;以后都别这么犯&quot;</li></ul><p><strong>新一代工程师最重要的能力：把企业的流程、知识、权限、风险、审计，沉淀成一套 Agent 可以消化、可以复用、可以持续迭代的 Harness 结构。</strong></p><hr><h2 id="分布式模式到-agent-模式的演进-血脉进化" tabindex="-1">分布式模式到 Agent 模式的演进（血脉进化） <a class="header-anchor" href="#分布式模式到-agent-模式的演进-血脉进化" aria-label="Permalink to &quot;分布式模式到 Agent 模式的演进（血脉进化）&quot;">​</a></h2><p>第二代和第三代之间是<strong>推进</strong>的关系，不是断裂。旧模式没有过时，是被抬高了一个层次。</p><table tabindex="0"><thead><tr><th>第二代分布式模式</th><th>第三代 Agent 模式的进化</th></tr></thead><tbody><tr><td>长事务补偿</td><td>规划—执行（Agent 任务不是一步完成，先拆任务，再执行，失败再重新规划）</td></tr></tbody></table><hr><h2 id="双轴正交框架的定位" tabindex="-1">双轴正交框架的定位 <a class="header-anchor" href="#双轴正交框架的定位" aria-label="Permalink to &quot;双轴正交框架的定位&quot;">​</a></h2><p>Agent 时代模式的核心张力不再是&quot;做什么对象操作&quot;，而是：</p><blockquote><p><strong>花什么资源 × 怎么花</strong></p></blockquote><ul><li>Y 轴（认知功能）回答：<strong>资源花在哪里</strong>（感知 / 记忆 / 推理 / 行动 / 反思 / 协作 / 治理）</li><li>X 轴（执行拓扑）回答：<strong>资源怎么花出去</strong>（链式 / 路由 / 并行 / 编排 / 循环 / 层级）</li></ul><hr><h2 id="思考题" tabindex="-1">思考题 <a class="header-anchor" href="#思考题" aria-label="Permalink to &quot;思考题&quot;">​</a></h2><ol><li>三代设计模式演进，根因分析是否到位？对你展望 Agent 时代新架构有何启发？</li><li>你的项目里写过哪几个 GoF 模式？挑 3 个用得最多的，说说它们各自的核心假设是什么？</li><li>你做过的微服务系统里用了 9 个分布式模式哪几个？哪些是生产系统不可或缺的？</li><li>你目前的项目里最关键的类（配置管理器、连接池、事件总线、策略容器），如果改造成 Agent 版本，会先碰到哪种断裂？</li><li>Harness vs Prompt：如果给你 1 周提升 Agent 可靠性，你选 (a) 调 prompt 让模型这次别犯错 / (b) 改 harness 让模型永远没机会犯错？为什么？</li></ol><hr><h2 id="关键对话总结" tabindex="-1">关键对话总结 <a class="header-anchor" href="#关键对话总结" aria-label="Permalink to &quot;关键对话总结&quot;">​</a></h2><p>以下内容来自学习过程中的互动讨论，帮助建立理论到实践的理解桥梁。</p><h3 id="_1-singleton-到底断在哪" tabindex="-1">1. Singleton 到底断在哪 <a class="header-anchor" href="#_1-singleton-到底断在哪" aria-label="Permalink to &quot;1. Singleton 到底断在哪&quot;">​</a></h3><p><strong>直觉</strong>：Agent 系统里 Singleton 没有用武之地，因为不需要全局唯一实例。</p><p><strong>根因</strong>：Singleton 的核心假设是&quot;状态全局共享，所有调用者看到同一份数据&quot;——这需要稳定的内存空间来保证。但 Agent 的工作空间是上下文窗口，窗口有 token 上限，每次对话可能被重置或压缩。</p><p><strong>暴露的真实需求</strong>：Agent 不是不需要全局状态，而是需要<strong>分层记忆架构</strong>来代替 Singleton 的&quot;全局性&quot;：</p><ul><li>工作记忆（当前上下文）</li><li>短期记忆（当前会话）</li><li>长期记忆（跨会话持久化）</li><li>程序性记忆（固化技能）</li></ul><p>问题层次被推高了一级——不是&quot;不要单例&quot;，是&quot;单例装不下现在的问题规模&quot;。</p><h3 id="_2-决策权搬家-四个断裂的根因" tabindex="-1">2. 决策权搬家：四个断裂的根因 <a class="header-anchor" href="#_2-决策权搬家-四个断裂的根因" aria-label="Permalink to &quot;2. 决策权搬家：四个断裂的根因&quot;">​</a></h3><p>GoF 所有模式隐含一个假设：<strong>架构师在设计时做出所有结构性决策。</strong> 编译时定好一切，运行时只管执行。</p><p>Agent 系统截然相反：<strong>模型在运行时、不确定性情况下做出决策。</strong></p><table tabindex="0"><thead><tr><th></th><th>GoF 时代</th><th>Agent 时代</th></tr></thead><tbody><tr><td>决策时机</td><td>编译期</td><td>运行时</td></tr><tr><td>执行方式</td><td>确定性执行</td><td>边规划边执行</td></tr><tr><td>不确定性角色</td><td>边缘情况（try-catch）</td><td>默认运行条件</td></tr></tbody></table><p>这个&quot;决策权从开发者搬到 LLM&quot;的转移，让 GoF 的 23 个模式集体失重：</p><table tabindex="0"><thead><tr><th>GoF 模式</th><th>断裂原因</th><th>Agent 替代方案</th></tr></thead><tbody><tr><td>Singleton</td><td>上下文窗口不保证全局性</td><td>分层记忆架构</td></tr><tr><td>Factory</td><td>动作空间在运行时开放</td><td>语义工具路由</td></tr><tr><td>Observer</td><td>全量推送撑爆上下文</td><td>主动感知（Agent 自己决定看什么）</td></tr><tr><td>Strategy</td><td>策略选择由 LLM 推理时动态切换</td><td>LLM 在 reason() 里每一步自己挑</td></tr></tbody></table><h3 id="_3-不确定性是默认条件-的两个比喻" tabindex="-1">3. &quot;不确定性是默认条件&quot;的两个比喻 <a class="header-anchor" href="#_3-不确定性是默认条件-的两个比喻" aria-label="Permalink to &quot;3. &quot;不确定性是默认条件&quot;的两个比喻&quot;">​</a></h3><p><strong>食堂打饭比喻</strong></p><ul><li>传统软件：排队 → 打菜 → 刷卡 → 走人。异常（队伍太长、余额不足）是意外情况，有应急预案。</li><li>Agent 系统：让实习生去打饭——&quot;随便打点好吃的&quot;。他到食堂发现菜跟昨天不一样（环境不确定）、刷卡余额不够（失败不确定）、碰到领导改变计划（行为不确定）。<strong>每一步都是现场决策，没有&quot;正常流程&quot;。</strong></li></ul><p><strong>开车 vs 自动驾驶</strong></p><ul><li>开车（传统软件）：知道终点在哪，90% 时间按计划行驶，堵车是异常。</li><li>自动驾驶（Agent 系统）：知道终点在哪，但路况每秒钟都在变。<strong>不是&quot;偶尔出状况&quot;，是&quot;状况才是常态&quot;。</strong></li></ul><blockquote><p>设计的时候就从&quot;系统会漂、会偏、会重复、会失控&quot;出发，不是从&quot;系统会完美执行&quot;出发。</p></blockquote><h3 id="_4-harness-的落地-你的真实案例" tabindex="-1">4. Harness 的落地：你的真实案例 <a class="header-anchor" href="#_4-harness-的落地-你的真实案例" aria-label="Permalink to &quot;4. Harness 的落地：你的真实案例&quot;">​</a></h3><p>你做过一个生成完整应用的 Agent，遇到了两个核心问题：</p><ol><li><strong>上下文爆炸</strong>——Agent 一次性承载太多信息</li><li><strong>生成成功率低</strong>——端到端一次性生成，出错后难以定位</li></ol><p>你的改进方案（这就是 Harness 的雏形）：</p><table tabindex="0"><thead><tr><th>你的做法</th><th>Harness 框架对应</th></tr></thead><tbody><tr><td>提前准备项目模板、通用代码</td><td><strong>限定动作空间</strong>——给模型边界，不是让它从零生成</td></tr><tr><td>先生成一个个子任务</td><td><strong>分解不确定性</strong>——大问题切成可控小块</td></tr><tr><td>每次只完成一个子任务</td><td><strong>编排 + 验证</strong>——每步可追溯、可回退</td></tr></tbody></table><p>你凭直觉找到的答案，正是这门课后面会系统性展开的**&quot;规划—执行&quot;模式**：不是让模型一次性做完，而是把大问题拆成小步骤，每一步给限制条件。</p><h3 id="_5-一句话带走" tabindex="-1">5. 一句话带走 <a class="header-anchor" href="#_5-一句话带走" aria-label="Permalink to &quot;5. 一句话带走&quot;">​</a></h3><blockquote><p><strong>模型负责花钱（token、时间、动作），Harness 负责管账。调 prompt 是局部修补让&quot;这次别犯&quot;，做 Harness 是把局部错误上升为系统纪律让&quot;以后都别这么犯&quot;。</strong></p></blockquote>`,111)])])}const q=a(s,[["render",l]]);export{c as __pageData,q as default};
